#!/usr/bin/perl
use strict;
use warnings;
use Storable qw(nstore retrieve lock_nstore lock_retrieve);
use File::Spec;
use File::Path qw(make_path);
use Digest::SHA qw(sha256_hex);
use Fcntl qw(:flock);
use CGI;
use CGI::Cookie;

# Configuration
my $SESSION_DIR = '/tmp/perl_sessions';
my $SESSION_EXPIRY = 3600;  # 1 hour in seconds
my $SESSION_ID_LENGTH = 64;

# Ensure session directory exists with restrictive permissions
unless (-d $SESSION_DIR) {
    make_path($SESSION_DIR, { mode => 0700 })
        or die "Cannot create session directory $SESSION_DIR: $!";
}

# Generate a cryptographically secure session ID
sub generate_session_id {
    my $random_bytes = '';
    if (open(my $fh, '<', '/dev/urandom')) {
        binmode($fh);
        read($fh, $random_bytes, 64);
        close($fh);
    } else {
        die "Cannot open /dev/urandom for secure random generation: $!";
    }
    return sha256_hex($random_bytes . time() . $$);
}

# Validate session ID format - only allow hex characters of exact expected length
sub validate_session_id {
    my ($session_id) = @_;
    return 0 unless defined $session_id;
    return 0 unless length($session_id) == $SESSION_ID_LENGTH;
    return 0 unless $session_id =~ /\A[0-9a-f]+\z/;
    return 1;
}

# Build a safe session file path, preventing directory traversal
sub get_session_filepath {
    my ($session_id) = @_;

    unless (validate_session_id($session_id)) {
        warn "Invalid session ID format rejected";
        return undef;
    }

    # Construct filename safely - session_id is already validated as hex-only
    my $filename = "sess_" . $session_id;

    # Use File::Spec to construct path safely
    my $filepath = File::Spec->catfile($SESSION_DIR, $filename);

    # Canonicalize and verify the path is within SESSION_DIR
    my $abs_session_dir = File::Spec->rel2abs($SESSION_DIR);
    my $abs_filepath = File::Spec->rel2abs($filepath);

    unless ($abs_filepath =~ /\A\Q$abs_session_dir\E\//) {
        warn "Path traversal attempt detected";
        return undef;
    }

    # Additional check: ensure no symlink in the path
    if (-e $abs_filepath && -l $abs_filepath) {
        warn "Symlink detected for session file, rejecting";
        return undef;
    }

    return $abs_filepath;
}

# Create a new session
sub create_session {
    my ($data) = @_;
    $data //= {};

    my $session_id = generate_session_id();
    my $filepath = get_session_filepath($session_id);

    unless ($filepath) {
        die "Failed to generate valid session filepath";
    }

    my $session_data = {
        _session_id  => $session_id,
        _created_at  => time(),
        _updated_at  => time(),
        _expires_at  => time() + $SESSION_EXPIRY,
        data         => $data,
    };

    # Store with file locking using lock_nstore for atomic writes
    eval {
        # Set restrictive umask before creating session file
        my $old_umask = umask(0077);
        lock_nstore($session_data, $filepath)
            or die "Cannot store session data: $!";
        umask($old_umask);
    };
    if ($@) {
        warn "Error creating session: $@";
        return undef;
    }

    # Verify file permissions
    chmod(0600, $filepath);

    return $session_id;
}

# Load an existing session
sub load_session {
    my ($session_id) = @_;

    my $filepath = get_session_filepath($session_id);
    unless ($filepath) {
        warn "Invalid session ID provided";
        return undef;
    }

    unless (-e $filepath && -f $filepath && !-l $filepath) {
        warn "Session file does not exist or is not a regular file";
        return undef;
    }

    # Check file ownership - must be owned by current user
    my @stat = stat($filepath);
    unless (@stat) {
        warn "Cannot stat session file: $!";
        return undef;
    }

    if ($stat[4] != $>) {
        warn "Session file ownership mismatch - possible tampering";
        return undef;
    }

    # Check file permissions are not too open
    my $perms = $stat[2] & 07777;
    if ($perms & 0077) {
        warn "Session file has insecure permissions";
        return undef;
    }

    my $session_data;
    eval {
        # Use lock_retrieve for safe concurrent access
        $session_data = lock_retrieve($filepath);
    };
    if ($@ || !$session_data) {
        warn "Error loading session: $@";
        unlink($filepath);  # Remove corrupted session file
        return undef;
    }

    # Validate session data structure
    unless (ref($session_data) eq 'HASH'
            && exists $session_data->{_session_id}
            && exists $session_data->{_expires_at}
            && exists $session_data->{_created_at}) {
        warn "Invalid session data structure";
        unlink($filepath);
        return undef;
    }

    # Verify session ID matches
    unless ($session_data->{_session_id} eq $session_id) {
        warn "Session ID mismatch in stored data";
        unlink($filepath);
        return undef;
    }

    # Check expiration
    if (time() > $session_data->{_expires_at}) {
        warn "Session expired";
        destroy_session($session_id);
        return undef;
    }

    return $session_data;
}

# Update session data
sub save_session {
    my ($session_id, $data) = @_;

    my $session_data = load_session($session_id);
    unless ($session_data) {
        warn "Cannot save: session not found or expired";
        return 0;
    }

    my $filepath = get_session_filepath($session_id);
    unless ($filepath) {
        return 0;
    }

    $session_data->{data} = $data;
    $session_data->{_updated_at} = time();
    $session_data->{_expires_at} = time() + $SESSION_EXPIRY;

    eval {
        my $old_umask = umask(0077);
        lock_nstore($session_data, $filepath)
            or die "Cannot store session data: $!";
        umask($old_umask);
    };
    if ($@) {
        warn "Error saving session: $@";
        return 0;
    }

    chmod(0600, $filepath);
    return 1;
}

# Destroy a session
sub destroy_session {
    my ($session_id) = @_;

    my $filepath = get_session_filepath($session_id);
    unless ($filepath) {
        return 0;
    }

    if (-e $filepath && !-l $filepath) {
        unlink($filepath) or warn "Cannot remove session file: $!";
    }

    return 1;
}

# Clean up expired sessions
sub cleanup_expired_sessions {
    opendir(my $dh, $SESSION_DIR) or do {
        warn "Cannot open session directory: $!";
        return;
    };

    my $cleaned = 0;
    while (my $entry = readdir($dh)) {
        next unless $entry =~ /\Asess_([0-9a-f]{$SESSION_ID_LENGTH})\z/;
        my $session_id = $1;
        my $filepath = get_session_filepath($session_id);
        next unless $filepath && -f $filepath && !-l $filepath;

        my @stat = stat($filepath);
        next unless @stat;

        # Skip files not owned by us
        next if $stat[4] != $>;

        eval {
            my $session_data = lock_retrieve($filepath);
            if ($session_data && ref($session_data) eq 'HASH'
                && exists $session_data->{_expires_at}
                && time() > $session_data->{_expires_at}) {
                unlink($filepath);
                $cleaned++;
            }
        };
        if ($@) {
            # Remove corrupted files
            unlink($filepath);
            $cleaned++;
        }
    }
    closedir($dh);

    return $cleaned;
}

# Get session ID from CGI cookie
sub get_session_id_from_cookie {
    my %cookies = CGI::Cookie->fetch();
    if (exists $cookies{'session_id'}) {
        my $session_id = $cookies{'session_id'}->value();
        if (validate_session_id($session_id)) {
            return $session_id;
        }
        warn "Invalid session ID in cookie rejected";
    }
    return undef;
}

# Create a session cookie
sub create_session_cookie {
    my ($session_id) = @_;

    unless (validate_session_id($session_id)) {
        die "Cannot create cookie with invalid session ID";
    }

    my $cookie = CGI::Cookie->new(
        -name     => 'session_id',
        -value    => $session_id,
        -expires  => '+1h',
        -path     => '/',
        -secure   => 1,
        -httponly  => 1,
        -samesite => 'Strict',
    );

    return $cookie;
}

# Create a cookie that destroys the session on the client
sub create_expired_cookie {
    my $cookie = CGI::Cookie->new(
        -name     => 'session_id',
        -value    => '',
        -expires  => '-1d',
        -path     => '/',
        -secure   => 1,
        -httponly  => 1,
        -samesite => 'Strict',
    );
    return $cookie;
}

