sub handle_request {
    my $cgi = CGI->new();

    # Periodically clean up expired sessions (1 in 100 requests)
    if (int(rand(100)) == 0) {
        cleanup_expired_sessions();
    }

    my $session_id = get_session_id_from_cookie();
    my $session_data;
    my $is_new_session = 0;

    # Try to load existing session
    if ($session_id) {
        $session_data = load_session($session_id);
    }

    # Create new session if needed
    unless ($session_data) {
        $session_id = create_session({ visit_count => 0 });
        unless ($session_id) {
            print $cgi->header(-status => '500 Internal Server Error',
                               -type => 'text/html');
            print "<html><body><h1>Session Error</h1></body></html>";
            return;
        }
        $session_data = load_session($session_id);
        $is_new_session = 1;
    }

    # Handle logout action
    my $action = $cgi->param('action') // '';
    if ($action eq 'logout') {
        destroy_session($session_id);
        my $expired_cookie = create_expired_cookie();
        print $cgi->header(
            -type    => 'text/html',
            -charset => 'UTF-8',
            -cookie  => $expired_cookie,
        );
        print "<html><body><h1>Logged Out</h1>";
        print "<p>Your session has been destroyed.</p>";
        print "<p><a href='?'>Start New Session</a></p>";
        print "</body></html>";
        return;
    }

    # Update session data
    my $user_data = $session_data->{data} // {};
    $user_data->{visit_count} = ($user_data->{visit_count} // 0) + 1;
    $user_data->{last_visit} = scalar localtime();
    $user_data->{user_agent} = $ENV{HTTP_USER_AGENT} // 'Unknown';

    save_session($session_id, $user_data);

    # Set cookie and output response
    my $cookie = create_session_cookie($session_id);

    print $cgi->header(
        -type    => 'text/html',
        -charset => 'UTF-8',
        -cookie  => $cookie,
    );

    # HTML-escape output to prevent XSS
    my $escaped_visit_count = _html_escape($user_data->{visit_count});
    my $escaped_last_visit  = _html_escape($user_data->{last_visit} // 'N/A');
    my $escaped_created     = _html_escape(scalar localtime($session_data->{_created_at}));
    my $escaped_expires     = _html_escape(scalar localtime($session_data->{_expires_at}));

    print <<"HTML";
<!DOCTYPE html>
<html>
<head><title>Session Demo</title></head>
<body>
<h1>Perl Session Management Demo</h1>
HTML

    if ($is_new_session) {
        print "<p><strong>New session created!</strong></p>\n";
    }

    print <<"HTML";
<h2>Session Information</h2>
<ul>
<li>Visit Count: $escaped_visit_count</li>
<li>Last Visit: $escaped_last_visit</li>
<li>Session Created: $escaped_created</li>
<li>Session Expires: $escaped_expires</li>
</ul>
<p><a href="?">Refresh</a> | <a href="?action=logout">Logout</a></p>
</body>
</html>
HTML
}

# HTML escape helper to prevent XSS
sub _html_escape {
    my ($str) = @_;
    return '' unless defined $str;
    $str =~ s/&/&amp;/g;
    $str =~ s/</&lt;/g;
    $str =~ s/>/&gt;/g;
    $str =~ s/"/&quot;/g;
    $str =~ s/'/&#39;/g;
    return $str;
}

